module.render:
const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const sup = (s) => esc(s).replace(/\^\{([^}]*)\}/g, '<sup>$1</sup>').replace(/\^(-?[\w.]+)/g, '<sup>$1</sup>');
let value = esc(String(args.value ?? '').trim());
const unc = String(args.unc ?? '').trim();
const unit = String(args.unit ?? '').trim();
const color = (args.color && String(args.color).trim()) || 'inherit';
const unitcolor = (args.unitcolor && String(args.unitcolor).trim()) || '';
const sci = String(args.sci) === 'true';
const bold = String(args.bold) === 'true';
if (sci) value = value.replace(/[eE]([+-]?\d+)/, '×10<sup>$1</sup>');
const cls = 'mdp-mod-quantity' + (bold ? ' mdp-qt-strong' : '');
const styleVars = `--qt-c:${color};` + (unitcolor ? ` --qt-unit-c:${unitcolor};` : '');
let out = `<span class="mdp-qt-val">${value}</span>`;
if (unc) out += `<span class="mdp-qt-unc"> ± ${esc(unc)}</span>`;
if (unit) out += `<span class="mdp-qt-unit"> ${sup(unit)}</span>`;
return `<span class="${cls}" style="${styleVars}">${out}</span>`;
